(function () {
    const form = document.querySelector('[data-search-form]');
    const input = document.querySelector('[data-search-input]');
    const result = document.querySelector('[data-search-result]');
    const params = new URLSearchParams(window.location.search);

    const escapeHtml = function (value) {
        return String(value || '').replace(/[&<>"']/g, function (char) {
            return {
                '&': '&amp;',
                '<': '&lt;',
                '>': '&gt;',
                '"': '&quot;',
                "'": '&#039;'
            }[char];
        });
    };

    const buildCard = function (movie) {
        const tags = movie.tags.slice(0, 2).map(function (tag) {
            return '<span>' + escapeHtml(tag) + '</span>';
        }).join('');

        return '<a class="movie-card" href="' + escapeHtml(movie.url) + '">' +
            '<span class="poster-frame">' +
                '<img src="' + escapeHtml(movie.cover) + '" alt="' + escapeHtml(movie.title) + '" loading="lazy">' +
                '<span class="poster-shade"></span>' +
                '<span class="poster-badge">' + escapeHtml(movie.type) + '</span>' +
            '</span>' +
            '<span class="card-body">' +
                '<strong>' + escapeHtml(movie.title) + '</strong>' +
                '<span class="card-desc">' + escapeHtml(movie.desc) + '</span>' +
                '<span class="card-meta">' + escapeHtml(movie.region) + ' · ' + escapeHtml(movie.year) + '</span>' +
                '<span class="tag-row">' + tags + '</span>' +
            '</span>' +
        '</a>';
    };

    const render = function (keyword) {
        if (!result) {
            return;
        }

        const q = String(keyword || '').trim().toLowerCase();
        let items = movieIndex;

        if (q) {
            items = movieIndex.filter(function (movie) {
                const text = [movie.title, movie.region, movie.type, movie.year, movie.genre, movie.desc, movie.tags.join(' ')].join(' ').toLowerCase();
                return text.includes(q);
            });
        } else {
            items = movieIndex.slice(0, 60);
        }

        if (items.length === 0) {
            result.innerHTML = '<div class="empty-state">没有找到相关影片</div>';
            return;
        }

        result.innerHTML = items.slice(0, 240).map(buildCard).join('');
    };

    if (input) {
        input.value = params.get('q') || '';
        input.addEventListener('input', function () {
            render(input.value);
        });
    }

    if (form) {
        form.addEventListener('submit', function (event) {
            event.preventDefault();
            render(input ? input.value : '');
        });
    }

    render(input ? input.value : '');
})();
